const __pageData = JSON.parse('{"title":"L6 横向贯穿：UI 原理在各层的映射","description":"将认知负荷理论、视觉感知原理、交互设计定律与设计系统理论从 UI/UX 领域映射到编程语言设计、API 设计、CLI 工具与文档站点信息架构中，揭示 UI 原理作为跨层次约束的理论基础，并探讨开发者体验（DX）作为 UI 原理在工具层的深层应用。","frontmatter":{"title":"L6 横向贯穿：UI 原理在各层的映射","description":"将认知负荷理论、视觉感知原理、交互设计定律与设计系统理论从 UI/UX 领域映射到编程语言设计、API 设计、CLI 工具与文档站点信息架构中，揭示 UI 原理作为跨层次约束的理论基础，并探讨开发者体验（DX）作为 UI 原理在工具层的深层应用。","date":"2026-05-01T00:00:00.000Z","tags":["UI-theory","cross-layer-mapping","cognitive-load","Fitts-law","Hicks-law","design-system","developer-experience","DX","API-design","theoretical-hierarchy"],"category":"theoretical-foundations"},"headers":[],"relativePath":"theoretical-hierarchy/06-ui-cross-layer-theory.md","filePath":"theoretical-hierarchy/06-ui-cross-layer-theory.md","lastUpdated":1777713329000}');
